import { Link } from 'react-router-dom'
import './Item.css'
export const Item = (props) => {
  return (
    <div className='item'>
        <Link to={''}><img src={props.image} alt=""/></Link>
        <p>{props.name}</p>
        <div className="iem-prices">
            <div className="item-price-new">
                ${props.new_price}
            </div>
            <div className="item-price-old">
                ${props.old_price}
            </div>
        </div>
    </div>
  )
}
